```java
import javax.swing.*;
import java.awt.*;
import java.util.ArrayList;
import java.util.List;
import java.util.Random;

public class NumberRainfall extends JPanel {

    private static final int PANEL_WIDTH = 1200;
    private static final int PANEL_HEIGHT = 800;
    private static final int RECT_WIDTH = 20;
    private static final int RECT_HEIGHT = 40;
    private static final int FALLING_SPEED = 1;  // don't change
    private static final int TIMER_SPEED = 30; // the real falling speed
    private static final Random RANDOM = new Random();

    private List<Rectangle> rectangles;

    public NumberRainfall(int numRectangles) {
        rectangles = new ArrayList<>();

        for (int i = 0; i < numRectangles; i++) {
            int xPosition = RANDOM.nextInt(PANEL_WIDTH - RECT_WIDTH);
            int yPosition = -RANDOM.nextInt(PANEL_HEIGHT);
            rectangles.add(new Rectangle(xPosition, yPosition));
        }
    }

    @Override
    protected void paintComponent(Graphics g) {
        super.paintComponent(g);

        Graphics2D g2d = (Graphics2D) g;
        g2d.setRenderingHint(RenderingHints.KEY_ANTIALIASING, RenderingHints.VALUE_ANTIALIAS_ON);

        for (Rectangle rectangle : rectangles) {
            g2d.fillRect(rectangle.getXPosition(), rectangle.getYPosition(), RECT_WIDTH, RECT_HEIGHT);
        }
    }

    public void startFallingAnimation() {
        Timer timer = new Timer(TIMER_SPEED, e -> {    // define falling speed
            for (Rectangle rectangle : rectangles) {
                rectangle.setYPosition(rectangle.getYPosition() + FALLING_SPEED);

                if (rectangle.getYPosition() >= PANEL_HEIGHT) {
                    rectangle.setXPosition(RANDOM.nextInt(PANEL_WIDTH - RECT_WIDTH));
                    rectangle.setYPosition(-RECT_HEIGHT);
                }
            }

            repaint();
        });
        timer.start();
    }

    private static class Rectangle {

        private int xPosition;
        private int yPosition;

        public Rectangle(int xPosition, int yPosition) {
            this.xPosition = xPosition;
            this.yPosition = yPosition;
        }

        public int getXPosition() {
            return xPosition;
        }

        public void setXPosition(int xPosition) {
            this.xPosition = xPosition;
        }

        public int getYPosition() {
            return yPosition;
        }

        public void setYPosition(int yPosition) {
            this.yPosition = yPosition;
        }
    }

    public static void main(String[] args) {
        SwingUtilities.invokeLater(() -> {
            int numRectangles = 100; // Define the number of falling rectangles

            JFrame frame = new JFrame("Number Rainfall");
            frame.setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);

            NumberRainfall numberRainfall = new NumberRainfall(numRectangles);
            frame.add(numberRainfall);

            frame.setSize(PANEL_WIDTH, PANEL_HEIGHT);
            frame.setVisible(true);

            numberRainfall.startFallingAnimation();
        });
    }
}
```

